const results = [];

for (const item of items) {
  const stdout = item.json.stdout || "";
  if (!stdout) continue;

  // หา IP
  const ipMatch = stdout.match(/Nmap scan report for\s+([0-9.]+)/);
  const ip = ipMatch ? ipMatch[1] : null;

  // แยกบรรทัด
  const lines = stdout.split("\n");

  for (const line of lines) {
    // จับบรรทัด port/service/version
    // ตัวอย่าง:
    // 22/tcp open  ssh     Dropbear sshd 2019.78 (protocol 2.0)
    // 53/tcp open  domain  (generic dns response: NXDOMAIN)
    const m = line.match(/^(\d+)\/tcp\s+open\s+(\S+)\s*(.*)$/);

    if (m) {
      const port = Number(m[1]);
      const service = m[2] || "";
      const version = (m[3] || "").trim();

      results.push({
        json: {
          ip,
          port,
          service,
          version,
          raw_line: line.trim()
        }
      });
    }
  }
}

return results;

function cleanText(v) {
  return String(v || "").replace(/\s+/g, " ").trim();
}

function serviceLabel(service, port) {
  const s = String(service || "").toLowerCase();

  if (s === "ssh" || port === 22) return "SSH";
  if (s === "domain" || port === 53) return "DNS";
  if (s.includes("http") || [80, 8080, 8008].includes(port)) return "HTTP";
  if (s.includes("ssl") || s.includes("https") || [443, 8443].includes(port)) return "HTTPS";
  if (s === "rtsp" || port === 554) return "RTSP";
  if (s === "rpcbind" || port === 111) return "RPCBIND";
  if ([135, 139, 445].includes(port)) return "SMB/RPC";
  if (port === 3000) return "APP";
  return String(service || "").toUpperCase();
}

function detectProduct(version) {
  const v = String(version || "");

  if (/dropbear/i.test(v)) return "Dropbear SSH";
  if (/openssh/i.test(v)) return "OpenSSH";
  if (/apache/i.test(v)) return "Apache HTTP Server";
  if (/nginx/i.test(v)) return "Nginx";
  if (/microsoft-iis/i.test(v)) return "Microsoft IIS";
  if (/node/i.test(v)) return "Node.js App";
  if (/dns/i.test(v)) return "DNS Service";

  return "";
}

const out = [];

for (const item of items) {
  const ip = cleanText(item.json.ip);
  const port = Number(item.json.port || 0);
  const protocol = "tcp";
  const service = cleanText(item.json.service).toLowerCase();
  const version = cleanText(item.json.version);
  const raw_line = cleanText(item.json.raw_line);

  const service_name = serviceLabel(service, port);
  const product = detectProduct(version);

  out.push({
    json: {
      ip,
      port,
      protocol,
      service,
      service_name,
      product,
      version,
      raw_line,
      exposed: true
    }
  });
}

return out;

const hosts = {};

for (const item of items) {

  const ip = item.json.ip;
  const port = item.json.port;

  if (!hosts[ip]) {
    hosts[ip] = [];
  }

  hosts[ip].push(port);
}

const results = [];

for (const ip in hosts) {

  results.push({
    json: {
      ip: ip,
      ports: hosts[ip].join(",")
    }
  });

}

return results;

const nowUTC = new Date().toISOString();
const nowTH = new Date().toLocaleString("sv-SE", { timeZone: "Asia/Bangkok" });

return items.map(item => {

  const ip = item.json.ip;
  const port = item.json.port;
  const protocol = item.json.protocol;

  const row_key = `${ip}_${port}_${protocol}`;

  return {
    json: {
      row_key,
      ip,
      port,
      protocol,
      service: item.json.service,
      service_name: item.json.service_name,
      product: item.json.product,
      version: item.json.version,
      exposed: item.json.exposed,
      first_seen: nowTH,
      last_seen: nowTH,
      scan_time_utc: nowUTC,
      scan_time_th: nowTH
    }
  };
});

function hasAny(text, keywords) {
  const t = String(text || "").toLowerCase();
  return keywords.some(k => t.includes(String(k).toLowerCase()));
}

function uniq(arr) {
  return [...new Set((arr || []).filter(Boolean))];
}

function addTag(tags, ...newTags) {
  return uniq([...(tags || []), ...newTags]);
}

function classifySeverity(score) {
  if (score >= 90) return "CRITICAL";
  if (score >= 70) return "HIGH";
  if (score >= 40) return "MEDIUM";
  return "LOW";
}

const out = [];

for (const item of items) {
  const ip = String(item.json.ip || "").trim();
  const port = Number(item.json.port || 0);
  const protocol = String(item.json.protocol || "tcp").trim().toLowerCase();
  const service = String(item.json.service || "").trim().toLowerCase();
  const service_name = String(item.json.service_name || "").trim();
  const product = String(item.json.product || "").trim();
  const version = String(item.json.version || "").trim();
  const raw_line = String(item.json.raw_line || "").trim();
  const row_key = String(item.json.row_key || `${ip}_${port}_${protocol}`).trim();

  const exposedRaw = item.json.exposed;
  const exposed = String(exposedRaw).toLowerCase() === "true" || exposedRaw === true;

  let risk_score = 10;
  let finding = "Service detected";
  let recommendation = "Review business necessity and close unused ports.";
  let tags = ["service-detected"];
  let rule_id = "SOC-GEN-001";

  // -----------------------------
  // 1) Legacy / Plaintext / Unsafe remote access
  // -----------------------------
  if (port === 23 || service === "telnet") {
    risk_score = 95;
    finding = "Telnet service exposed";
    recommendation = "Disable Telnet immediately and replace it with SSH. Restrict management access to trusted hosts only.";
    tags = addTag(tags, "telnet", "plaintext", "legacy", "remote-access");
    rule_id = "SOC-RA-001";
  }

  else if (port === 21 || service === "ftp") {
    risk_score = 80;
    finding = "FTP service exposed";
    recommendation = "Avoid plaintext FTP. Migrate to SFTP/FTPS, restrict source IPs, and disable anonymous access.";
    tags = addTag(tags, "ftp", "plaintext", "file-transfer", "remote-access");
    rule_id = "SOC-RA-002";
  }

  else if (port === 20) {
    risk_score = 70;
    finding = "FTP data channel exposed";
    recommendation = "Review whether active-mode FTP is required. Prefer secure alternatives and restrict access.";
    tags = addTag(tags, "ftp", "legacy", "plaintext");
    rule_id = "SOC-RA-003";
  }

  else if (port === 3389 || service === "ms-wbt-server") {
    risk_score = 90;
    finding = "RDP service exposed";
    recommendation = "Restrict RDP behind VPN/firewall, enforce MFA if available, and monitor login attempts.";
    tags = addTag(tags, "rdp", "remote-access", "windows");
    rule_id = "SOC-RA-004";
  }

  else if (port === 5900 || service === "vnc") {
    risk_score = 78;
    finding = "VNC service exposed";
    recommendation = "Restrict VNC behind VPN/firewall, require strong authentication, and disable if unnecessary.";
    tags = addTag(tags, "vnc", "remote-access", "desktop-sharing");
    rule_id = "SOC-RA-005";
  }

  // -----------------------------
  // 2) SSH
  // -----------------------------
  else if (port === 22 || service === "ssh") {
    risk_score = 45;
    finding = "SSH service exposed";
    recommendation = "Restrict source IPs, prefer key-based authentication, disable password login where possible, and rotate credentials.";
    tags = addTag(tags, "ssh", "remote-access", "admin-service");
    rule_id = "SOC-SSH-001";

    if (hasAny(product, ["dropbear"]) || hasAny(version, ["dropbear"])) {
      risk_score = 55;
      finding = "SSH service exposed (Dropbear detected)";
      recommendation = "Review firmware/software updates, restrict source IPs, and harden SSH settings for embedded/Linux devices.";
      tags = addTag(tags, "dropbear", "embedded-linux", "iot");
      rule_id = "SOC-SSH-002";
    }

    if (hasAny(version, ["openssh 5", "openssh 6", "openssh_5", "openssh_6"])) {
      risk_score = 78;
      finding = "SSH service exposed with potentially outdated OpenSSH version";
      recommendation = "Verify installed OpenSSH version and update to a supported release. Review cipher/KEX hardening.";
      tags = addTag(tags, "outdated-ssh", "patching");
      rule_id = "SOC-SSH-003";
    }
  }

  // -----------------------------
  // 3) Windows / Lateral movement
  // -----------------------------
  else if ([135, 139, 445].includes(port) || ["msrpc", "netbios-ssn", "microsoft-ds"].includes(service)) {
    risk_score = 88;
    finding = "Windows RPC/SMB-related service exposed";
    recommendation = "Restrict SMB/RPC to trusted segments only, verify patch status, and do not expose to untrusted networks.";
    tags = addTag(tags, "windows", "smb", "rpc", "lateral-movement");
    rule_id = "SOC-WIN-001";
  }

  else if (port === 137 || port === 138) {
    risk_score = 72;
    finding = "NetBIOS service exposed";
    recommendation = "Restrict legacy Windows name/file-sharing traffic and disable if not required.";
    tags = addTag(tags, "windows", "netbios", "legacy");
    rule_id = "SOC-WIN-002";
  }

  // -----------------------------
  // 4) Web / Admin / App ports
  // -----------------------------
  else if (
    [80, 443, 8080, 8443, 8008, 8009, 3000, 5000, 5601, 9090, 9091].includes(port) ||
    hasAny(service_name, ["HTTP", "HTTPS"]) ||
    hasAny(service, ["http", "https"])
  ) {
    risk_score = 50;
    finding = "Web service exposed";
    recommendation = "Review exposed web applications, patch software, protect admin interfaces, and restrict management panels.";
    tags = addTag(tags, "web", "http", "app");
    rule_id = "SOC-WEB-001";

    if ([8008, 8009, 8443, 3000, 5000, 5601, 9090, 9091].includes(port)) {
      risk_score = 62;
      finding = "Alternative web/application port exposed";
      recommendation = "Verify whether this web/admin/application port must be reachable. Restrict or proxy it if unnecessary.";
      tags = addTag(tags, "alt-web-port", "admin-surface");
      rule_id = "SOC-WEB-002";
    }

    if (port === 443 || port === 8443) {
      tags = addTag(tags, "tls-surface");
    }

    if (hasAny(product, ["nginx", "apache", "iis"])) {
      tags = addTag(tags, "web-server");
    }
  }

  // -----------------------------
  // 5) DNS / Infra services
  // -----------------------------
  else if (port === 53 || service === "domain") {
    risk_score = 20;
    finding = "DNS service detected";
    recommendation = "Ensure recursion and zone transfer are restricted appropriately and expose only where required.";
    tags = addTag(tags, "dns", "infra-service");
    rule_id = "SOC-INFRA-001";
  }

  else if (port === 111 || service === "rpcbind") {
    risk_score = 55;
    finding = "rpcbind service exposed";
    recommendation = "Restrict rpcbind exposure to internal hosts only and disable it if unused.";
    tags = addTag(tags, "rpcbind", "linux", "infra-service");
    rule_id = "SOC-INFRA-002";
  }

  else if (port === 123 || service === "ntp") {
    risk_score = 25;
    finding = "NTP service detected";
    recommendation = "Ensure NTP is restricted to trusted networks and not susceptible to abuse or amplification.";
    tags = addTag(tags, "ntp", "infra-service");
    rule_id = "SOC-INFRA-003";
  }

  else if (port === 161 || service === "snmp") {
    risk_score = 60;
    finding = "SNMP service exposed";
    recommendation = "Restrict SNMP to trusted hosts, avoid default community strings, and prefer SNMPv3.";
    tags = addTag(tags, "snmp", "network-device", "infra-service");
    rule_id = "SOC-INFRA-004";
  }

  // -----------------------------
  // 6) Database exposure
  // -----------------------------
  else if ([1433, 1521, 3306, 5432, 6379, 27017, 9200].includes(port)) {
    risk_score = 90;
    finding = "Database or data platform port exposed";
    recommendation = "Restrict access to application hosts only, require authentication, and never expose data services unnecessarily.";
    tags = addTag(tags, "database", "data-platform", "high-value-target");
    rule_id = "SOC-DATA-001";

    if (port === 6379) {
      finding = "Redis service port exposed";
      recommendation = "Restrict Redis to internal networks only, require authentication where supported, and disable unsafe remote access.";
      tags = addTag(tags, "redis");
      rule_id = "SOC-DATA-002";
    }

    if (port === 9200) {
      finding = "Elasticsearch API port exposed";
      recommendation = "Restrict Elasticsearch access, require authentication, and prevent public exposure.";
      tags = addTag(tags, "elasticsearch", "search-cluster");
      rule_id = "SOC-DATA-003";
    }
  }

  // -----------------------------
  // 7) IoT / Camera / Messaging
  // -----------------------------
  else if (port === 554 || service === "rtsp") {
    risk_score = 78;
    finding = "RTSP/IP camera service exposed";
    recommendation = "Change default credentials, restrict access, and isolate cameras on a separate VLAN or security zone.";
    tags = addTag(tags, "camera", "rtsp", "iot", "video-surveillance");
    rule_id = "SOC-IOT-001";
  }

  else if (port === 1883 || port === 8883 || service === "mqtt") {
    risk_score = 65;
    finding = "MQTT service exposed";
    recommendation = "Require authentication, use TLS where possible, and restrict broker access to trusted devices and applications.";
    tags = addTag(tags, "mqtt", "iot", "message-broker");
    rule_id = "SOC-IOT-002";
  }

  else if (port === 5683 || service === "coap") {
    risk_score = 68;
    finding = "CoAP service exposed";
    recommendation = "Restrict CoAP to trusted IoT segments and review device-level authentication and encryption controls.";
    tags = addTag(tags, "coap", "iot");
    rule_id = "SOC-IOT-003";
  }

  // -----------------------------
  // 8) Email / Directory / Auth services
  // -----------------------------
  else if ([25, 465, 587].includes(port) || service === "smtp") {
    risk_score = 35;
    finding = "SMTP service detected";
    recommendation = "Verify whether the host should provide mail services and ensure relay controls are configured.";
    tags = addTag(tags, "smtp", "mail-service");
    rule_id = "SOC-MAIL-001";
  }

  else if ([110, 995].includes(port) || service === "pop3") {
    risk_score = 40;
    finding = "POP3 service exposed";
    recommendation = "Prefer modern secure mail access methods and restrict unnecessary exposure.";
    tags = addTag(tags, "pop3", "mail-service");
    rule_id = "SOC-MAIL-002";
  }

  else if ([143, 993].includes(port) || service === "imap") {
    risk_score = 35;
    finding = "IMAP service exposed";
    recommendation = "Ensure secure configuration and restrict unnecessary exposure.";
    tags = addTag(tags, "imap", "mail-service");
    rule_id = "SOC-MAIL-003";
  }

  else if ([389, 636].includes(port) || service === "ldap") {
    risk_score = 70;
    finding = "Directory service exposed";
    recommendation = "Restrict LDAP/LDAPS to trusted networks only and verify authentication and encryption settings.";
    tags = addTag(tags, "ldap", "directory-service", "identity");
    rule_id = "SOC-ID-001";
  }

  else if (port === 88 || service === "kerberos") {
    risk_score = 75;
    finding = "Kerberos service exposed";
    recommendation = "Ensure this identity service is not unnecessarily exposed beyond trusted internal zones.";
    tags = addTag(tags, "kerberos", "identity", "windows");
    rule_id = "SOC-ID-002";
  }

  // -----------------------------
  // 9) Unknown high ports / custom services
  // -----------------------------
  else if (port >= 1024 && port <= 65535) {
    risk_score = 30;
    finding = "Non-standard service port detected";
    recommendation = "Validate whether this custom or dynamic service port is expected and restrict access where appropriate.";
    tags = addTag(tags, "non-standard-port");
    rule_id = "SOC-GEN-002";
  }

  // -----------------------------
  // 10) Exposure adjustment
  // -----------------------------
  if (!exposed) {
    risk_score = Math.max(5, risk_score - 15);
    tags = addTag(tags, "not-confirmed-exposed");
  } else {
    tags = addTag(tags, "exposed");
  }

  // -----------------------------
  // 11) Text-based heuristics
  // -----------------------------
  if (hasAny(version, ["generic dns response", "unrecognized"])) {
    tags = addTag(tags, "fingerprint-limited");
  }

  if (hasAny(product, ["dropbear", "mikrotik", "busybox"]) || hasAny(version, ["dropbear", "busybox"])) {
    tags = addTag(tags, "embedded-device");
  }

  if (hasAny(raw_line, ["ssl", "tls"]) || [443, 465, 636, 993, 995, 8443, 8883].includes(port)) {
    tags = addTag(tags, "encrypted-service");
  }

  const risk_level = classifySeverity(risk_score);
  const severity_rank =
    risk_level === "CRITICAL" ? 4 :
    risk_level === "HIGH" ? 3 :
    risk_level === "MEDIUM" ? 2 : 1;

  out.push({
    json: {
      row_key,
      ip,
      port,
      protocol,
      service,
      service_name,
      product,
      version,
      raw_line,
      exposed,

      rule_id,
      risk_level,
      severity_rank,
      risk_score,
      finding,
      recommendation,
      tags: uniq(tags).join(",")
    }
  });
}

return out;

// CODE | Build Risk Finding Row
// Mode: Run Once for Each Item

function clean(v) {
  return String(v ?? '').trim();
}

function nowTH() {
  const now = new Date();
  const th = new Date(now.getTime() + (7 * 60 * 60 * 1000));
  return th.toISOString().replace('Z', '+07:00');
}

function calcThreatLevel(ruleRisk, cvss, cveFound, kevExploited) {
  const r = clean(ruleRisk).toUpperCase();
  const s = Number(cvss ?? 0);

  // ถ้าอยู่ใน CISA KEV ให้ยกระดับทันที
  if (kevExploited) return 'CRITICAL';

  if (cveFound && s >= 9.0) return 'CRITICAL';
  if (cveFound && s >= 7.0) return 'HIGH';
  if (cveFound && s >= 4.0) return 'MEDIUM';

  if (r === 'CRITICAL') return 'CRITICAL';
  if (r === 'HIGH') return 'HIGH';
  if (r === 'MEDIUM') return 'MEDIUM';
  if (r === 'LOW') return 'LOW';

  return 'INFO';
}

function calcSecurityScore(ruleRiskScore, cvss, cveCount, kevExploited) {
  const risk = Number(ruleRiskScore ?? 0);
  const score = Number(cvss ?? 0);
  const count = Number(cveCount ?? 0);

  let total = Math.round(risk + (score * 5) + Math.min(count * 3, 15));

  // ถ้าเป็น KEV ให้บวกน้ำหนักเพิ่ม
  if (kevExploited) total += 20;

  return total;
}

function calcSecurityGrade(score) {
  if (score >= 90) return 'F';
  if (score >= 75) return 'D';
  if (score >= 60) return 'C';
  if (score >= 40) return 'B';
  return 'A';
}

function calcRiskIndex(threatLevel, securityScore, kevExploited) {
  const t = clean(threatLevel).toUpperCase();

  if (kevExploited) return `KEV-${securityScore}`;
  if (t === 'CRITICAL') return `CRI-${securityScore}`;
  if (t === 'HIGH') return `HIG-${securityScore}`;
  if (t === 'MEDIUM') return `MED-${securityScore}`;
  if (t === 'LOW') return `LOW-${securityScore}`;
  return `INF-${securityScore}`;
}

const j = $json;

const rule_risk = clean(j.risk_level);
const risk_score = Number(j.risk_score ?? 0);

const cve_found = !!j.cve_found;
const cve_ids = Array.isArray(j.cve_ids)
  ? j.cve_ids
  : clean(j.cve_ids)
      .split(',')
      .map(x => x.trim())
      .filter(Boolean);

const cve_count = Number(j.cve_count ?? 0);
const max_cvss_score = Number(j.max_cvss_score ?? 0);
const cve_severity = clean(j.cve_severity || 'INFO');
const cve_confidence = clean(j.cve_confidence || 'no_reliable_match');

const kev_exploited = !!j.kev_exploited;
const kev_cve = clean(j.kev_cve);
const kev_source = clean(j.kev_source || '');

const threat_level = calcThreatLevel(rule_risk, max_cvss_score, cve_found, kev_exploited);
const security_score = calcSecurityScore(risk_score, max_cvss_score, cve_count, kev_exploited);
const security_grade = calcSecurityGrade(security_score);
const risk_index = calcRiskIndex(threat_level, security_score, kev_exploited);

return {
  json: {
    finding_key: clean(j.finding_key || j.row_key),
    row_key: clean(j.row_key),

    detected_at: nowTH(),

    ip: clean(j.ip),
    port: j.port ?? '',
    protocol: clean(j.protocol),

    service: clean(j.service),
    service_name: clean(j.service_name),
    product: clean(j.product),
    version_raw: clean(j.version_raw),
    version_number: clean(j.version_number),

    exposed: !!j.exposed,

    rule_id: clean(j.rule_id),
    rule_risk,
    risk_score,
    severity_rank: Number(j.severity_rank ?? 0),

    finding: clean(j.finding),
    recommendation: clean(j.recommendation),
    tags: clean(j.tags),

    cve_search_query: clean(j.cve_search_query),
    nvd_total_results: Number(j.nvd_total_results ?? 0),
    cve_found,
    cve_confidence,
    cve_ids: cve_ids.join(','),
    cve_count,
    top_cve_id: clean(j.top_cve_id),
    top_cve_description: clean(j.top_cve_description),
    top_cve_relevance_score: Number(j.top_cve_relevance_score ?? 0),
    max_cvss_score,
    cve_severity,

    kev_exploited,
    kev_cve,
    kev_source,

    threat_level,
    security_score,
    security_grade,
    risk_index
  }
};

// CODE | Prepare CVE Query
// Mode: Run Once for Each Item

function clean(v) {
  return String(v ?? '').trim();
}

function normSpaces(v) {
  return clean(v).replace(/\s+/g, ' ');
}

function lower(v) {
  return normSpaces(v).toLowerCase();
}

function pickFirst(...vals) {
  for (const v of vals) {
    const s = normSpaces(v);
    if (s) return s;
  }
  return '';
}

function extractVersionNumber(versionRaw = '') {
  const v = normSpaces(versionRaw);

  // เช่น 7.2 / 1.18.0 / 2.4.49 / 2019.78
  const m = v.match(/\b\d+(?:\.\d+){0,3}\b/);
  return m ? m[0] : '';
}

function normalizeProduct(service, product, serviceName) {
  const s = lower(service);
  const p = normSpaces(product);
  const sn = normSpaces(serviceName);

  if (p) return p;

  if (s === 'ssh') return 'OpenSSH';
  if (s === 'http') return 'Apache httpd';
  if (s === 'https') return 'Apache httpd';
  if (s === 'ftp') return 'FTP';
  if (s === 'telnet') return 'Telnet';
  if (s === 'mysql') return 'MySQL';
  if (s === 'postgresql') return 'PostgreSQL';
  if (s === 'redis') return 'Redis';
  if (s === 'mongodb') return 'MongoDB';
  if (s === 'ms-wbt-server') return 'Remote Desktop';
  if (s === 'microsoft-ds') return 'SMB';

  return sn || service || 'unknown-service';
}

function buildStrictQuery(product, service, versionNumber) {
  const p = normSpaces(product);
  const s = lower(service);
  const v = clean(versionNumber);

  if (!v) return p || service || '';

  if (lower(p).includes('dropbear')) return `Dropbear ${v}`;
  if (lower(p).includes('openssh')) return `OpenSSH ${v}`;
  if (lower(p).includes('apache')) return `Apache httpd ${v}`;
  if (lower(p).includes('nginx')) return `nginx ${v}`;
  if (lower(p).includes('microsoft iis')) return `Microsoft IIS ${v}`;
  if (lower(p).includes('mysql')) return `MySQL ${v}`;
  if (lower(p).includes('postgresql')) return `PostgreSQL ${v}`;
  if (lower(p).includes('redis')) return `Redis ${v}`;
  if (lower(p).includes('mongodb')) return `MongoDB ${v}`;

  if (s === 'ssh') return `OpenSSH ${v}`;
  if (s === 'http') return `Apache httpd ${v}`;
  if (s === 'https') return `Apache httpd ${v}`;
  if (s === 'mysql') return `MySQL ${v}`;
  if (s === 'redis') return `Redis ${v}`;
  if (s === 'mongodb') return `MongoDB ${v}`;

  return `${p || service} ${v}`.trim();
}

