// CODE | Parse CVE Result
// Mode: Run Once for Each Item

function clean(v) {
  return String(v ?? '').trim();
}

function norm(v) {
  return clean(v).toLowerCase();
}

function arr(v) {
  return Array.isArray(v) ? v : [];
}

function uniq(values) {
  return [...new Set(arr(values).filter(Boolean))];
}

function getEnglishDescription(cve) {
  const descs = arr(cve?.descriptions);
  const en = descs.find(d => d?.lang === 'en');
  return clean(en?.value);
}

function extractCvss(cve) {
  const metrics = cve?.metrics || {};

  const v31 = arr(metrics.cvssMetricV31);
  if (v31.length > 0) {
    const x = v31[0];
    return {
      cvss_score: Number(x?.cvssData?.baseScore ?? 0),
      severity: clean(x?.cvssData?.baseSeverity || x?.baseSeverity || '')
    };
  }

  const v30 = arr(metrics.cvssMetricV30);
  if (v30.length > 0) {
    const x = v30[0];
    return {
      cvss_score: Number(x?.cvssData?.baseScore ?? 0),
      severity: clean(x?.cvssData?.baseSeverity || x?.baseSeverity || '')
    };
  }

  const v2 = arr(metrics.cvssMetricV2);
  if (v2.length > 0) {
    const x = v2[0];
    return {
      cvss_score: Number(x?.cvssData?.baseScore ?? 0),
      severity: clean(x?.baseSeverity || '')
    };
  }

  return {
    cvss_score: 0,
    severity: ''
  };
}

function scoreSeverity(cvss) {
  if (cvss >= 9.0) return 'CRITICAL';
  if (cvss >= 7.0) return 'HIGH';
  if (cvss >= 4.0) return 'MEDIUM';
  if (cvss > 0) return 'LOW';
  return 'INFO';
}

function extractVersionHints(versionNumber, versionRaw) {
  const hints = [];
  const v1 = clean(versionNumber);
  const v2 = clean(versionRaw);

  if (v1) hints.push(v1);

  const m = v2.match(/\b\d+(?:\.\d+){0,3}\b/g);
  if (m) hints.push(...m);

  return uniq(hints);
}

function buildMatchKeywords(src) {
  const product = clean(src.product);
  const service = clean(src.service);
  const serviceName = clean(src.service_name);
  const keywordBase = clean(src.keyword_base);
  const strictQuery = clean(src.search_query_strict);
  const normalQuery = clean(src.search_query);

  const keywords = [
    product,
    service,
    serviceName,
    keywordBase
  ];

  const p = norm(product);
  if (p.includes('dropbear')) keywords.push('dropbear');
  if (p.includes('openssh')) keywords.push('openssh');
  if (p.includes('apache')) keywords.push('apache');
  if (p.includes('nginx')) keywords.push('nginx');
  if (p.includes('mysql')) keywords.push('mysql');
  if (p.includes('postgresql')) keywords.push('postgresql');
  if (p.includes('redis')) keywords.push('redis');
  if (p.includes('mongodb')) keywords.push('mongodb');

  for (const q of [strictQuery, normalQuery]) {
    const parts = clean(q)
      .split(/\s+/)
      .map(x => x.trim())
      .filter(x => x && x.length >= 3 && !/^\d+(\.\d+){0,3}$/.test(x));
    keywords.push(...parts);
  }

  return uniq(
    keywords
      .map(k => clean(k))
      .filter(Boolean)
      .map(k => k.toLowerCase())
  );
}

function relevanceScore(text, keywords, versionHints) {
  let score = 0;
  const t = norm(text);

  for (const k of keywords) {
    if (!k) continue;

    if (t.includes(k)) score += 3;

    if (
      ['dropbear', 'openssh', 'apache', 'nginx', 'mysql', 'postgresql', 'redis', 'mongodb'].includes(k) &&
      t.includes(k)
    ) {
      score += 4;
    }
  }

  for (const v of versionHints) {
    if (v && t.includes(v.toLowerCase())) score += 2;
  }

  return score;
}

function pickTopCve(list) {
  let top = null;
  for (const item of list) {
    if (
      !top ||
      item.relevance_score > top.relevance_score ||
      (item.relevance_score === top.relevance_score && item.cvss_score > top.cvss_score)
    ) {
      top = item;
    }
  }
  return top;
}

