const api = $json;

// src = output จาก CODE | Prepare CVE Query
const src = $('CODE | Prepare CVE Query').item.json;

// ---------- source fields ----------
const row_key = clean(src.row_key);
const finding_key = clean(src.finding_key);

const ip = clean(src.ip);
const port = src.port ?? '';
const protocol = clean(src.protocol);

const service = clean(src.service);
const service_name = clean(src.service_name);
const product = clean(src.product);

const version_raw = clean(src.version_raw || src.version);
const version_number = clean(src.version_number);

const keyword_base = clean(src.keyword_base);
const search_query = clean(src.search_query);
const search_query_strict = clean(src.search_query_strict);

const rule_id = clean(src.rule_id);
const risk_level = clean(src.risk_level);
const risk_score = Number(src.risk_score ?? 0);
const severity_rank = Number(src.severity_rank ?? 0);

const finding = clean(src.finding);
const recommendation = clean(src.recommendation);
const tags = clean(src.tags);
const exposed = !!src.exposed;

// ---------- api response ----------
const vulnerabilities = arr(api.vulnerabilities);
const matchKeywords = buildMatchKeywords(src);
const versionHints = extractVersionHints(version_number, version_raw);

const scored = vulnerabilities.map(v => {
  const cve = v?.cve || {};
  const description = getEnglishDescription(cve);
  const metric = extractCvss(cve);
  const severity = metric.severity || scoreSeverity(metric.cvss_score);
  const rel = relevanceScore(description, matchKeywords, versionHints);

  return {
    cve_id: clean(cve.id),
    published: clean(cve.published),
    last_modified: clean(cve.lastModified),
    vuln_status: clean(cve.vulnStatus),
    description,
    cvss_score: metric.cvss_score,
    severity,
    relevance_score: rel
  };
});

let filtered = scored.filter(x => x.relevance_score >= 3);

filtered.sort((a, b) => {
  if (b.relevance_score !== a.relevance_score) {
    return b.relevance_score - a.relevance_score;
  }
  return b.cvss_score - a.cvss_score;
});

const parsed = filtered.slice(0, 5);
const top_cve = pickTopCve(parsed);

const cve_ids = parsed.map(x => x.cve_id).filter(Boolean);
const cve_count = parsed.length;
const max_cvss_score = top_cve?.cvss_score ?? 0;
const cve_severity = top_cve?.severity ?? 'INFO';

return {
  json: {
    row_key,
    finding_key,

    ip,
    port,
    protocol,

    service,
    service_name,
    product,

    version_raw,
    version_number,

    keyword_base,
    search_query,
    search_query_strict,

    rule_id,
    risk_level,
    risk_score,
    severity_rank,

    finding,
    recommendation,
    tags,
    exposed,

    resultsPerPage: Number(api.resultsPerPage ?? 0),
    startIndex: Number(api.startIndex ?? 0),
    totalResults: Number(api.totalResults ?? 0),
    format: clean(api.format),
    version: clean(api.version),
    timestamp: clean(api.timestamp),

    cve_search_query: search_query_strict || search_query,
    cve_match_keywords: matchKeywords,
    cve_version_hints: versionHints,
    nvd_total_results: Number(api.totalResults ?? 0),

    cve_results: parsed,
    cve_ids,
    cve_count,

    top_cve_id: top_cve?.cve_id ?? '',
    top_cve_description: top_cve?.description ?? '',
    top_cve_relevance_score: top_cve?.relevance_score ?? 0,
    max_cvss_score,
    cve_severity,

    cve_found: cve_count > 0,
    cve_confidence: cve_count > 0 ? 'matched' : 'no_reliable_match'
  }
};

